// Parse + Normalize AI Agent output into ONE canonical item.
// Works whether AI Agent returns JSON object OR JSON-as-string in output/text/content.

function tryParseJson(s) {
  if (typeof s !== 'string') return null;
  try { return JSON.parse(s); } catch { return null; }
}

function extractJsonFromText(s) {
  // If model returns extra text, try to grab the first JSON object.
  if (typeof s !== 'string') return null;
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const candidate = s.slice(start, end + 1);
    return tryParseJson(candidate);
  }
  return null;
}

function getAgentPayload(j) {
  // Common LangChain Agent output shapes
  // - { output: "..." }
  // - { text: "..." }
  // - { ...actualObject }
  // - { message: { content: "..." } } etc.
  if (j && typeof j === 'object' && Array.isArray(j.required_response_structure)) return j;
  if (j && typeof j === 'object' && j.required_response_structure) return j;

  const candidates = [];

  if (typeof j === 'string') candidates.push(j);
  if (j?.output) candidates.push(j.output);
  if (j?.text) candidates.push(j.text);
  if (j?.message?.content) candidates.push(j.message.content);
  if (j?.choices?.[0]?.message?.content) candidates.push(j.choices[0].message.content);

  for (const c of candidates) {
    const parsed = tryParseJson(c) || extractJsonFromText(c);
    if (parsed && (parsed.required_response_structure || parsed.compliance_checklist)) return parsed;
  }

  // last resort: maybe the entire input item is the parsed object already
  if (j && typeof j === 'object') return j;

  throw new Error("Could not parse AI Agent output into JSON.");
}

const raw = $json;
const parsed = getAgentPayload(raw);

// ---- Basic schema guard (fail early, fail clearly)
const requiredTopKeys = [
  "rfp_id","rfp_title","client_org","procurement_type",
  "submission_deadline","submission_method",
  "formatting_requirements","required_response_structure",
  "compliance_checklist","evaluation_criteria",
  "appendices_and_forms","open_questions"
];
for (const k of requiredTopKeys) {
  if (!(k in parsed)) throw new Error(`AI output missing required key: ${k}`);
}

const all = [parsed]; // canonicalize as if it were a list

const isObj = (v) => v && typeof v === 'object' && !Array.isArray(v);
const asArray = (v) => Array.isArray(v) ? v : (v == null ? [] : [v]);

function pickFirst(key) {
  for (const it of all) if (it?.[key] != null) return it[key];
  return null;
}

// Header fields
const rfp_id = pickFirst("rfp_id");
const rfp_title = pickFirst("rfp_title");
const client_org = pickFirst("client_org");
const procurement_type = pickFirst("procurement_type");
const submission_deadline = pickFirst("submission_deadline");
const submission_method = pickFirst("submission_method");

// 1) Sections (ensure array)
let sections = [];
if (Array.isArray(parsed.required_response_structure)) sections = parsed.required_response_structure;
else if (isObj(parsed.required_response_structure)) sections = [parsed.required_response_structure];

const sectionMap = new Map();
for (const s of sections) {
  if (!s?.title && !s?.section_id) continue;

  const normalized = {
    section_id: (s.section_id ? String(s.section_id) : "").trim(),
    title: (s.title ?? "").toString().trim(),
    is_mandatory: s.is_mandatory !== false,
    order: Number.isFinite(Number(s.order)) ? Number(s.order) : null,
    required_content: asArray(s.required_content).filter(Boolean).map(x => String(x).trim()),
    page_or_word_limit: s.page_or_word_limit ?? null,
    evaluation_alignment: asArray(s.evaluation_alignment).filter(Boolean).map(x => String(x).trim()),
    source_quotes: asArray(s.source_quotes).filter(Boolean).map(x => String(x).trim()).slice(0, 2),
  };

  // Dedupe by title if section_id missing
  const key = normalized.section_id || normalized.title || `idx_${sectionMap.size+1}`;
  if (!sectionMap.has(key)) sectionMap.set(key, normalized);
}

let required_response_structure = Array.from(sectionMap.values());

// infer + sort + renumber
required_response_structure.forEach(s => {
  if (!s.order) {
    const m = /^S(\d+)$/.exec(s.section_id);
    if (m) s.order = Number(m[1]);
  }
});
required_response_structure.sort((a,b) => (a.order ?? 999) - (b.order ?? 999));
required_response_structure = required_response_structure.map((s, idx) => ({
  ...s,
  order: idx + 1,
  section_id: `S${idx + 1}`
}));

// 2) Formatting requirements normalize
let formatting = {
  page_limit: null,
  font: null,
  font_size: null,
  file_format: null,
  language: null,
  other_constraints: []
};

if (isObj(parsed.formatting_requirements)) {
  formatting = {
    page_limit: parsed.formatting_requirements.page_limit ?? null,
    font: parsed.formatting_requirements.font ?? null,
    font_size: parsed.formatting_requirements.font_size ?? null,
    file_format: parsed.formatting_requirements.file_format ?? null,
    language: parsed.formatting_requirements.language ?? null,
    other_constraints: asArray(parsed.formatting_requirements.other_constraints).map(String).map(s => s.trim()).filter(Boolean)
  };
}

// 3) Overall expectations (global rules)
let overall_expectations = [...formatting.other_constraints];
for (const s of required_response_structure) {
  if (/format|submission|requirements on the format/i.test(s.title)) {
    overall_expectations.push(...(s.required_content || []));
  }
}
overall_expectations = Array.from(new Set(overall_expectations.map(s => String(s).trim()).filter(Boolean)));

return [{
  json: {
    rfp_id,
    rfp_title,
    client_org,
    procurement_type,
    submission_deadline,
    submission_method,
    formatting_requirements: formatting,
    required_response_structure,
    overall_expectations,

    // keep the full original extraction too (debug + traceability)
    _raw_extraction: parsed
  }
}];

// Attach Sheet ID to the canonical+insights object (NOT the pre-insights canonical)
const base = $items('Code in JavaScript1')[0]?.json;
if (!base) throw new Error('Missing base item from Code in JavaScript1.');

const created = $('Create sheet').first().json;
const sheetId = created.sheetId;

if (!sheetId) throw new Error('Create sheet did not return sheetId.');

return [{
  json: { ...base, sheetId }
}];

const headers = [
  "rfp_id","rfp_title","client_org","procurement_type",
  "submission_deadline_date","submission_deadline_time","submission_deadline_timezone",
  "submission_method_channel","submission_method_details",

  "section_id","order","title","is_mandatory","page_or_word_limit",
  "required_content","evaluation_alignment","source_quotes",

  // section-targeted outputs (from section agent)
  "section_summary","what_evaluators_want","human_inputs_needed",
  "questions_for_humans","evidence_to_pull","drafting_outline",

  // global outputs (from global agent)
  "executive_takeaways","win_themes","risks","go_no_go_flags",
  "clarification_questions","critical_human_contributions",

  "tender_insights_json",
  "sheetId"
];

const row = {};
for (const h of headers) row[h] = h;

return [{ json: row }];

// Parse AI Agent1 output into { tender_insights: { insights_block, section_insights } }
// AND enforce section_insights keys to match canonical S1/S2/S3... from Build AI Agent Input.

// ---------- helpers ----------
function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try { return JSON.parse(s); } catch { return null; }
}
function extractJsonFromText(s) {
  if (typeof s !== "string") return null;
  const start = s.indexOf("{");
  const end = s.lastIndexOf("}");
  if (start >= 0 && end > start) {
    return tryParseJson(s.slice(start, end + 1));
  }
  return null;
}
function getAgentPayload(j) {
  // If already parsed object
  if (j && typeof j === "object" && (j.insights_block || j.section_insights)) return j;

  const candidates = [];
  if (typeof j === "string") candidates.push(j);
  if (j?.output) candidates.push(j.output);
  if (j?.text) candidates.push(j.text);
  if (j?.message?.content) candidates.push(j.message.content);
  if (j?.choices?.[0]?.message?.content) candidates.push(j.choices[0].message.content);

  for (const c of candidates) {
    const parsed = tryParseJson(c) || extractJsonFromText(c);
    if (parsed && (parsed.insights_block || parsed.section_insights)) return parsed;
  }

  // last resort: return original if object
  if (j && typeof j === "object") return j;

  throw new Error("Could not parse AI Agent1 output into JSON.");
}

// ---------- parse ----------
const raw = $json;
const parsed = getAgentPayload(raw);

// ---------- schema guard ----------
if (!parsed.insights_block) throw new Error("AI Agent1 output missing insights_block");
if (!parsed.section_insights) throw new Error("AI Agent1 output missing section_insights");

// ---------- key enforcement ----------
const canonical = $items("Build AI Agent Input")[0]?.json?.tender;
if (!canonical) throw new Error("Missing canonical tender from Build AI Agent Input");

const canonIds = (canonical.required_response_structure || []).map(s => s.section_id);
const returnedIds = Object.keys(parsed.section_insights || {});

const sameSet =
  returnedIds.length === canonIds.length &&
  canonIds.every(id => returnedIds.includes(id));

if (!sameSet) {
  // Fail-safe remap by ORDER if lengths match
  const canonSorted = [...(canonical.required_response_structure || [])]
    .sort((a,b) => (a.order || 999) - (b.order || 999));

  const returnedEntries = Object.entries(parsed.section_insights || {});

  if (returnedEntries.length === canonSorted.length) {
    const remapped = {};
    for (let i = 0; i < canonSorted.length; i++) {
      remapped[canonSorted[i].section_id] = returnedEntries[i][1];
    }
    parsed.section_insights = remapped;
  } else {
    throw new Error(
      `section_insights keys mismatch. Expected ${canonIds.join(", ")} but got ${returnedIds.join(", ")}`
    );
  }
}

// ---------- output ----------
return [{ json: { tender_insights: parsed } }];

// Build Agent1 Input
// Goal: give Agent1 the full canonical tender JSON + key ToR clauses (concise)
// so it can produce a high-signal human brief.

const tender = $json; // output of Parse and Normalize (canonical)

// Pull raw extracted PDF text (optional). Keep it short to avoid token bloat.
const torText = ($('Extract from File').item.json.text || '').toString();
const torTextShort = torText.length > 12000 ? torText.slice(0, 12000) : torText;

// Build “key clauses” from canonical fields (most important for humans)
const clauses = [];

// Formatting rules are explicit in ToR Ch.7 (10 pages excl CVs, font >=11, English, no links, etc.)
if (tender?.formatting_requirements?.page_limit) clauses.push(`Page limit: ${tender.formatting_requirements.page_limit} pages (excl. CVs)`);
if (tender?.formatting_requirements?.font_size) clauses.push(`Font size: ${tender.formatting_requirements.font_size}`);
if (tender?.formatting_requirements?.language) clauses.push(`Language: ${tender.formatting_requirements.language}`);
for (const c of (tender?.formatting_requirements?.other_constraints || [])) clauses.push(c);

// Overall expectations (deduped already in your normalize node)
for (const c of (tender?.overall_expectations || [])) clauses.push(c);

const keyClauses = Array.from(new Set(clauses.map(s => String(s).trim()).filter(Boolean))).slice(0, 30);

return [{
  json: {
    tender,                 // canonical object (single source of truth)
    key_clauses: keyClauses, // concise bullets
    tor_text_excerpt: torTextShort, // optional; remove if you want stricter canonical-only
    file: {
      id: $('Download file').item.json.id,
      name: $('Download file').item.json.name,
    }
  }
}];

const items = $input.all().map(i => i.json);

const canonical = items.find(x => x.required_response_structure && x.formatting_requirements);
const insights = items.find(x => x.tender_insights)?.tender_insights;

if (!canonical) throw new Error("Missing canonical item from merge.");
if (!insights) throw new Error("Missing tender_insights item from merge.");

return [{
  json: {
    ...canonical,
    tender_insights: insights
  }
}];

// Build a rich, section-scoped input for Agent2 (while preserving the full item)

const tender = $json;

const section = tender.required_response_structure ?? tender.section ?? {};
const section_id = section.section_id ?? tender.section_id ?? null;

const sheetId = tender.sheetId ?? tender.sheet_id ?? null;
const merge_key =
  tender.merge_key ??
  (sheetId && section_id ? `${sheetId}::${section_id}` : (section_id ?? null));

const raw = tender._raw_extraction ?? {};
const compliance = raw.compliance_checklist ?? tender.compliance_checklist ?? [];

const mappedIds = [String(section_id || ""), String(section_id || "").replace(/^S/i, "")]
  .filter(Boolean);

const compliance_for_section = (Array.isArray(compliance) ? compliance : []).filter(c =>
  Array.isArray(c.mapped_section_ids) &&
  c.mapped_section_ids.some(id => mappedIds.includes(String(id)))
);

const agent2_input = {
  rfp_meta: {
    rfp_id: tender.rfp_id ?? null,
    rfp_title: tender.rfp_title ?? null,
    client_org: tender.client_org ?? null,
    procurement_type: tender.procurement_type ?? null,
  },

  // Helpful global context (if present)
  overall_expectations: tender.overall_expectations ?? null,
  formatting_requirements: tender.formatting_requirements ?? raw.formatting_requirements ?? null,
  open_questions_global: raw.open_questions ?? tender.open_questions ?? null,
  evaluation_criteria: raw.evaluation_criteria ?? tender.evaluation_criteria ?? null,

  // Section scope
  section: {
    section_id: section.section_id ?? section_id,
    title: section.title ?? null,
    order: section.order ?? null,
    is_mandatory: section.is_mandatory ?? null,
    page_or_word_limit: section.page_or_word_limit ?? null,
    required_content: section.required_content ?? [],
    evaluation_alignment: section.evaluation_alignment ?? [],
    source_quotes: section.source_quotes ?? [],
  },

  // Compliance items mapped to this section (when available)
  compliance_checklist_for_section: compliance_for_section,

  // Agent1 insights are useful as fallback / cross-check
  global_insights: tender.tender_insights?.insights_block ?? null,
  section_insight_fallback_from_agent1: tender.tender_insights?.section_insights?.[section_id] ?? null,
};

return {
  json: {
    ...tender,
    merge_key,
    agent2_input
  }
};

function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try {
    return JSON.parse(s);
  } catch {
    // common LLM issue: literal newlines inside quoted strings -> invalid JSON
    try {
      return JSON.parse(s.replace(/\r?\n/g, "\\n"));
    } catch {
      return null;
    }
  }
}

function extractJson(s) {
  if (typeof s !== "string") return null;
  const start = s.indexOf("{");
  const end = s.lastIndexOf("}");
  if (start >= 0 && end > start) return tryParseJson(s.slice(start, end + 1));
  return null;
}

function toList(v) {
  if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
  if (typeof v === "string") {
    return v
      .split(/\r?\n/)
      .map(line => line.replace(/^\s*(?:•|-|\*|\d+[\).\:-])\s*/,"").trim())
      .filter(Boolean);
  }
  return [];
}

function ensureFiveQuestions(list, requiredContent) {
  let out = Array.isArray(list) ? list.slice(0, 5) : [];
  if (out.length < 5) {
    const rc = Array.isArray(requiredContent) ? requiredContent : [];
    for (let i = out.length; i < 5; i++) {
      const topic = rc[i] || rc[0] || "this section";
      out.push(`What specific information, evidence, or decisions do we need to provide about: ${topic}?`);
    }
  }
  return out;
}

// Identify section_id from the most reliable place available
const sectionFromInput = $json.agent2_input?.section ?? $json.required_response_structure ?? {};
const sectionIdFallback =
  sectionFromInput.section_id ??
  $json.section_id ??
  ($json.merge_key ? String($json.merge_key).split("::").pop() : null);

// n8n AI Agent can return structured fields, or a string under output/text/message.content, etc.
const rawCandidates = [
  $json.output,
  $json.text,
  $json.message?.content,
  $json.choices?.[0]?.message?.content,
];

let parsed = null;

// Case 1: Output parser merged structured fields into top-level JSON
if ($json && typeof $json === "object" && ($json.section_summary || $json.questions_for_humans || $json.what_evaluators_want)) {
  parsed = $json;
}

// Case 2: Parse from a likely string/object field
if (!parsed) {
  let raw = rawCandidates.find(v => v != null);
  if (!raw) raw = $json;

  if (typeof raw === "object") {
    parsed = (raw.output && typeof raw.output === "object") ? raw.output : raw;
  } else {
    parsed = tryParseJson(raw) || extractJson(raw);
  }
}

if (!parsed || typeof parsed !== "object") {
  throw new Error("Agent2 output not parseable JSON");
}

// Sometimes wrapped: { data: {...} }
if (!parsed.section_summary && parsed.data && typeof parsed.data === "object") {
  parsed = parsed.data;
}

const requiredContent = sectionFromInput.required_content ?? [];
const section_id = parsed.section_id ?? sectionIdFallback;

if (!section_id) {
  throw new Error("Agent2 output missing section_id (and no fallback found)");
}

const normalized = {
  section_id,
  section_summary: (typeof parsed.section_summary === "string" && parsed.section_summary.trim()) ? parsed.section_summary.trim() : null,
  what_evaluators_want: toList(parsed.what_evaluators_want),
  human_inputs_needed: toList(parsed.human_inputs_needed),
  questions_for_humans: ensureFiveQuestions(toList(parsed.questions_for_humans), requiredContent),
  evidence_to_pull: toList(parsed.evidence_to_pull),
  drafting_outline: toList(parsed.drafting_outline),
};

// Fallback to Agent1 section_insights if Agent2 omitted content
const fallback =
  $json.tender_insights?.section_insights?.[section_id] ??
  $json.agent2_input?.section_insight_fallback_from_agent1 ??
  {};

if (!normalized.section_summary && typeof fallback.section_summary === "string") normalized.section_summary = fallback.section_summary;
if (!normalized.what_evaluators_want.length && Array.isArray(fallback.what_evaluators_want)) normalized.what_evaluators_want = fallback.what_evaluators_want;
if (!normalized.human_inputs_needed.length && Array.isArray(fallback.human_inputs_needed)) normalized.human_inputs_needed = fallback.human_inputs_needed;
if (!normalized.evidence_to_pull.length && Array.isArray(fallback.evidence_to_pull)) normalized.evidence_to_pull = fallback.evidence_to_pull;
if (!normalized.drafting_outline.length && Array.isArray(fallback.drafting_outline)) normalized.drafting_outline = fallback.drafting_outline;

// Must be exactly 5
normalized.questions_for_humans = ensureFiveQuestions(normalized.questions_for_humans, requiredContent);
if (!Array.isArray(normalized.questions_for_humans) || normalized.questions_for_humans.length !== 5) {
  throw new Error("Agent2 output: questions_for_humans must be exactly 5 items after normalization");
}

// IMPORTANT: output ONLY what Merge2 needs
return {
  json: {
    merge_key: $json.merge_key,
    section_pack: normalized
  }
};

// Keep ONLY what Merge2 needs: merge_key + section_pack
return {
  json: {
    merge_key: $json.merge_key,
    section_pack: $json.section_pack
  }
};

const sec = $json.required_response_structure;

// Guard: Split Out must output one section object per item
if (!sec || typeof sec !== "object" || Array.isArray(sec)) {
  throw new Error("Add merge_key: required_response_structure must be an object. Place this node AFTER Split Out.");
}

const sheetId = $json.sheetId ?? "noSheet";
const sectionId = sec.section_id ?? `idx_${$itemIndex}`;
const merge_key = `${sheetId}::${sectionId}`;

return {
  json: {
    ...$json,
    merge_key,
  },
};

function asArray(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === "string" && v.trim()) return [v.trim()];
  return [];
}

function bullet(list) {
  const arr = asArray(list).map(x => String(x).trim()).filter(Boolean);
  if (!arr.length) return null;
  return arr.map(x => `• ${x}`).join("\n");
}

function bulletFromObjects(arr, fmt) {
  if (!Array.isArray(arr) || !arr.length) return null;
  return arr.map(x => `• ${fmt(x)}`).join("\n");
}

function formatWinThemes(winThemes) {
  return bulletFromObjects(winThemes, (t) => {
    const theme = t.theme ? String(t.theme) : "Theme";
    const so = t.so_what ? String(t.so_what) : "";
    const proof = Array.isArray(t.proof_needed) ? t.proof_needed.join("; ") : "";
    return `${theme}${so ? ` — ${so}` : ""}${proof ? ` (Proof: ${proof})` : ""}`;
  });
}

function formatRisks(risks) {
  return bulletFromObjects(risks, (r) => {
    const risk = r.risk ? String(r.risk) : "Risk";
    const impact = r.impact ? String(r.impact) : "";
    const mit = r.mitigation ? String(r.mitigation) : "";
    const owner = r.owner ? String(r.owner) : "";
    const parts = [];
    if (impact) parts.push(`impact: ${impact}`);
    if (mit) parts.push(`mitigation: ${mit}`);
    if (owner) parts.push(`owner: ${owner}`);
    return `${risk}${parts.length ? ` — ${parts.join(" | ")}` : ""}`;
  });
}

function formatClarifications(cq, section_id) {
  const arr = Array.isArray(cq) ? cq : [];
  const filtered = section_id
    ? arr.filter(x => Array.isArray(x.blocks) ? x.blocks.includes(section_id) : true)
    : arr;

  return bulletFromObjects(filtered, (x) => {
    const q = x.question ? String(x.question) : "";
    const why = x.why ? String(x.why) : "";
    return `${q}${why ? ` — ${why}` : ""}`;
  });
}

function formatCriticalContrib(cc) {
  return bulletFromObjects(cc, (x) => {
    const area = x.area ? String(x.area) : "Area";
    const who = x.who_to_ask ? String(x.who_to_ask) : "";
    const qs = Array.isArray(x.questions_to_ask) ? x.questions_to_ask.join("; ") : "";
    return `${area}${who ? ` (Ask: ${who})` : ""}${qs ? ` — Questions: ${qs}` : ""}`;
  });
}

// ---- Main
const tender = $json;
const section = tender.required_response_structure ?? {};
const section_id = section.section_id ?? tender.section_id ?? null;

// Prefer Agent2 pack; fall back to Agent1 section_insights if needed
const pack =
  tender.section_pack ??
  tender.tender_insights?.section_insights?.[section_id] ??
  {};

const insights = tender.tender_insights?.insights_block ?? {};

// Build the final row (matches your existing Google Sheet column mapping)
const row = {
  sheetId: tender.sheetId ?? null,
  rfp_id: tender.rfp_id ?? null,
  rfp_title: tender.rfp_title ?? null,
  client_org: tender.client_org ?? null,
  procurement_type: tender.procurement_type ?? null,

  submission_deadline_date: tender.submission_deadline?.date ?? null,
  submission_deadline_time: tender.submission_deadline?.time_local ?? null,
  submission_deadline_timezone: tender.submission_deadline?.timezone ?? null,

  submission_method_channel: tender.submission_method?.channel ?? null,
  submission_method_details: tender.submission_method?.details ?? null,

  section_id,
  order: section.order ?? null,
  title: section.title ?? null,
  is_mandatory: section.is_mandatory ?? null,
  page_or_word_limit: section.page_or_word_limit ?? null,

  required_content: bullet(section.required_content),
  evaluation_alignment: bullet(section.evaluation_alignment),
  source_quotes: bullet(section.source_quotes),

  section_summary: pack.section_summary ?? null,
  what_evaluators_want: bullet(pack.what_evaluators_want),
  human_inputs_needed: bullet(pack.human_inputs_needed),
  questions_for_humans: bullet(pack.questions_for_humans),
  evidence_to_pull: bullet(pack.evidence_to_pull),
  drafting_outline: bullet(pack.drafting_outline),

  executive_takeaways: bullet(insights.executive_takeaways),
