  submission_method_details: tender.submission_method?.details ?? null,

  section_id,
  order: section.order ?? null,
  title: section.title ?? null,
  is_mandatory: section.is_mandatory ?? null,
  page_or_word_limit: section.page_or_word_limit ?? null,

  required_content: bullet(section.required_content),
  evaluation_alignment: bullet(section.evaluation_alignment),
  source_quotes: bullet(section.source_quotes),

  section_summary: pack.section_summary ?? null,
  what_evaluators_want: bullet(pack.what_evaluators_want),
  human_inputs_needed: bullet(pack.human_inputs_needed),
  questions_for_humans: bullet(pack.questions_for_humans),
  evidence_to_pull: bullet(pack.evidence_to_pull),
  drafting_outline: bullet(pack.drafting_outline),

  executive_takeaways: bullet(insights.executive_takeaways),
  win_themes: formatWinThemes(insights.win_themes),
  risks: formatRisks(insights.risks),
  go_no_go_flags: bullet(insights.go_no_go_flags),

  // section-scoped subset for usability
  clarification_questions: formatClarifications(insights.clarification_questions_global, section_id),

  critical_human_contributions: formatCriticalContrib(insights.critical_human_contributions),

  // keep the full machine-readable payload too
  tender_insights_json: JSON.stringify({
    insights_block: insights,
    section_insights: tender.tender_insights?.section_insights ?? null
  }),
};

return { json: row };

// Pass-through node: keep ALL fields from AI Agent2 output.
// Only ensure section_id is present for downstream fallback logic.

const section_id =
  $json.agent2_input?.section?.section_id ??
  $json.required_response_structure?.section_id ??
  $json.section_id ??
  ($json.merge_key ? String($json.merge_key).split("::").pop() : null);

return {
  json: {
    ...$json,
    section_id
  }
};
